"""stl_validator_improved.py — improved STL validation tool.

Handles both ASCII and binary STL files.
Checks:
 - Triangle count
 - Surface area
 - Volume (via divergence theorem)
 - Manifold integrity (open edges AND non-manifold edges)
 - Face normal consistency (correct threshold)
 - Degenerate triangles
 - Duplicate triangles
"""
import json
import math
import struct
import sys


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return v
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def _signed_tet_volume(v1, v2, v3):
    """Signed volume of tetrahedron formed by origin and triangle."""
    return _dot(v1, _cross(v2, v3)) / 6.0


def _is_binary_stl(path: str) -> bool:
    """Detect if STL file is binary format."""
    with open(path, 'rb') as f:
        header = f.read(80)
        if len(header) < 80:
            return False
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            return False
        triangle_count = struct.unpack('<I', count_bytes)[0]
        expected_size = 80 + 4 + triangle_count * 50
        import os
        actual_size = os.path.getsize(path)
        # If sizes match, likely binary; also check it doesn't start with 'solid'
        # (ASCII starts with 'solid', but some binary files also start with 'solid')
        if actual_size == expected_size and triangle_count > 0:
            return True
    # Check if it starts with 'solid' (ASCII indicator)
    with open(path, 'r', errors='replace') as f:
        first_line = f.readline().strip().lower()
    return not first_line.startswith('solid')


def parse_binary_stl(path: str):
    """Parse binary STL file. Returns list of (normal, [v1, v2, v3])."""
    triangles = []
    issues = []
    with open(path, 'rb') as f:
        f.read(80)  # skip header
        count_bytes = f.read(4)
        if len(count_bytes) < 4:
            issues.append("Binary STL: could not read triangle count")
            return triangles, issues
        triangle_count = struct.unpack('<I', count_bytes)[0]
        for i in range(triangle_count):
            data = f.read(50)
            if len(data) < 50:
                issues.append(f"Binary STL: truncated at triangle {i+1}")
                break
            vals = struct.unpack('<12fH', data)
            normal = (vals[0], vals[1], vals[2])
            v1 = (vals[3], vals[4], vals[5])
            v2 = (vals[6], vals[7], vals[8])
            v3 = (vals[9], vals[10], vals[11])
            triangles.append((normal, [v1, v2, v3]))
    return triangles, issues


def parse_ascii_stl(path: str):
    """Parse ASCII STL file. Returns list of (normal, [v1, v2, v3])."""
    issues = []
    triangles = []

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue

        i += 1

    return triangles, issues


def validate_stl(path: str) -> dict:
    issues = []

    # Detect format and parse
    try:
        is_binary = _is_binary_stl(path)
    except Exception as e:
        return {"valid": False, "issues": [f"Could not read file: {e}"]}

    if is_binary:
        triangles, parse_issues = parse_binary_stl(path)
    else:
        triangles, parse_issues = parse_ascii_stl(path)

    issues.extend(parse_issues)

    if not triangles:
        issues.append("No valid faces found")
        return {
            "valid": False,
            "triangle_count": 0,
            "surface_area": 0.0,
            "volume": 0.0,
            "issues": issues,
        }

    # Degenerate triangle check
    degenerate_count = 0
    for _, verts in triangles:
        area = _triangle_area(*verts)
        if area < 1e-10:
            degenerate_count += 1
    if degenerate_count > 0:
        issues.append(f"Found {degenerate_count} degenerate (zero-area) triangle(s)")

    # Duplicate triangle check
    seen_triangles = set()
    duplicate_count = 0
    for _, verts in triangles:
        key = tuple(sorted(tuple(round(x, 6) for x in v) for v in verts))
        if key in seen_triangles:
            duplicate_count += 1
        else:
            seen_triangles.add(key)
    if duplicate_count > 0:
        issues.append(f"Found {duplicate_count} duplicate triangle(s)")

    # Manifold check: every edge must be shared by exactly 2 triangles.
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    non_manifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)

    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")
    if non_manifold_edges > 0:
        issues.append(f"Mesh has {non_manifold_edges} non-manifold edge(s) (shared by >2 triangles)")

    # Normal consistency check (FIXED threshold):
    # Declared normal should be aligned with winding-order normal.
    # similarity should be > 0 (same hemisphere). Threshold at 0.0.
    # We flag normals that are anti-parallel (similarity < 0)
    # BUG IN ORIGINAL: threshold was -0.99, only catching perfect inversions.
    inverted_normals = 0
    misaligned_normals = 0
    for declared_normal, verts in triangles:
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        cross = _cross(edge1, edge2)
        if _magnitude(cross) < 1e-10:
            continue  # degenerate triangle, skip
        winding_normal = _normalize(cross)
        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            # zero declared normal is allowed in some STL conventions, skip
            continue
        similarity = _dot(_normalize(declared_normal), winding_normal)
        if similarity < -0.99:
            inverted_normals += 1
        elif similarity < 0.0:
            # Misaligned but not perfectly inverted - also wrong
            misaligned_normals += 1

    if inverted_normals > 0:
        issues.append(f"{inverted_normals} face(s) have inverted normals (similarity < -0.99)")
    if misaligned_normals > 0:
        issues.append(f"{misaligned_normals} face(s) have misaligned normals (0 > similarity >= -0.99) — missed by original validator")

    # Surface area
    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    # Volume (signed, via divergence theorem)
    volume = sum(_signed_tet_volume(*verts) for _, verts in triangles)
    # Volume should be positive for correctly-oriented mesh
    if open_edges == 0 and non_manifold_edges == 0:
        if volume < 0:
            issues.append(f"Computed volume is negative ({volume:.6f}) — normals may be pointing inward")
        elif abs(volume) < 1e-10:
            issues.append("Computed volume is ~0 — mesh may be a surface, not a solid")

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "volume": round(abs(volume), 6),
        "format": "binary" if is_binary else "ascii",
        "issues": issues,
    }


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved.py <file.stl>"}))
        sys.exit(1)
    result = validate_stl(sys.argv[1])
    print(json.dumps(result, indent=2))
